class Solution:
    def countOfPairs(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        m = max(nums)
        dp = [0] * (m + 1)
        for j in range(nums[0] + 1):
            dp[j] = 1
        for i in range(1, n):
            ndp = [0] * (m + 1)
            for j in range(nums[i] + 1):
                total = 0
                for kk in range(0, nums[i - 1] + 1):
                    if kk <= j and (nums[i - 1] - kk) >= (nums[i] - j):
                        total += dp[kk]
                ndp[j] = total % MOD
            dp = ndp
        return sum(dp) % MOD

