        for i in range(1, n):
            prefix = [0] * (m + 2)
            for j in range(m + 1):
                prefix[j + 1] = (prefix[j] + dp[j]) % MOD
            diff = nums[i - 1] - nums[i]
            shift = min(0, diff)
            ndp = [0] * (m + 1)
            for j in range(nums[i] + 1):
                U = j + shift
                if U < 0:
                    continue
                if U > m:
                    U = m
                ndp[j] = prefix[U + 1]
            dp = ndp
