var countOfPairs = function(nums) {
    const MOD = 1000000007;
    const n = nums.length;
    let m = 0;
    for (const v of nums) if (v > m) m = v;
    let dp = new Array(m + 1).fill(0);
    for (let j = 0; j <= nums[0]; j++) dp[j] = 1;
    for (let i = 1; i < n; i++) {
        const prefix = new Array(m + 2).fill(0);
        for (let j = 0; j <= m; j++) prefix[j + 1] = (prefix[j] + dp[j]) % MOD;
        const diff = nums[i - 1] - nums[i];
        const shift = Math.min(0, diff);
        const ndp = new Array(m + 1).fill(0);
        for (let j = 0; j <= nums[i]; j++) {
            let U = j + shift;
            if (U < 0) continue;
            if (U > m) U = m;
            ndp[j] = prefix[U + 1];
        }
        dp = ndp;
    }
    let total = 0;
    for (const v of dp) total = (total + v) % MOD;
    return total;
};
